import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"プロジェクトの作成","description":"Fabric テンプレート Mod ジェネレータを使用した Mod 作成の段階的なガイド。","frontmatter":{"title":"プロジェクトの作成","description":"Fabric テンプレート Mod ジェネレータを使用した Mod 作成の段階的なガイド。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ja_jp/1.21.1/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.1/translated/ja_jp/develop/getting-started/creating-a-project.md","lastUpdated":1761424914000}`);var l={name:`ja_jp/1.21.1/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">プロジェクトの作成 <a class="header-anchor" href="#h1" aria-label="Permalink to “プロジェクトの作成”">​</a></h1><p>Fabric は、Mod プロジェクトを簡単に作成することを可能にする Fabric テンプレート Mod ジェネレータを提供しています。手動でプロジェクトを作成したい場合は、サンプルの Mod リポジトリを使用することができます。<a href="#manual-project-creation">手動で作成する</a> セクションを参照してください。</p><h2 id="generating-a-project" tabindex="-1">プロジェクトの生成 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “プロジェクトの生成”">​</a></h2><p><a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric テンプレート Mod ジェネレータ</a> を使用すると新しいプロジェクトを生成することができます。パッケージ名、Mod 名、Mod が対応する Minecraft バージョンの入力が必要です。</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="ジェネレータのプレビュー" loading="lazy"></p><p>Kotlin を使用したい場合や、データ生成を行いたい場合は、<code>Advanced Options</code> セクションで適切なオプションを選択してください。</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Advanced Options セクション" loading="lazy"></p><p>必要な項目の入力が完了したら、<code>Generate</code> ボタンを押してください。ジェネレータが新しいプロジェクトを zip ファイル形式で生成します。</p><p>zip ファイルを任意の場所で解凍して、解凍されたフォルダを IntelliJ IDEA で開いてください。</p><p><img src="/assets/develop/getting-started/open-project.png" alt="プロジェクトを開く 画面" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">プロジェクトのインポート <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “プロジェクトのインポート”">​</a></h2><p>プロジェクトを IntelliJ IDEA で開くと、IDE は自動で Gradle 設定を読み込み、セットアップに必要なタスクを行います。</p><p>Gradle ビルドスクリプトに関する通知が表示された場合は、<code>Gradle プロジェクトのインポート</code> ボタンを押してください:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle プロンプト" loading="lazy"></p><p>プロジェクトのインポートが完了すると、プロジェクトツールウィンドウにファイルが表示され、Mod の開発を始めることができるようになります。</p><h2 id="manual-project-creation" tabindex="-1">手動によるプロジェクトの作成 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “手動によるプロジェクトの作成”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>サンプルの Mod リポジトリをクローンするためには、<a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> のインストールが必要になります。</p></div><p>Fabric テンプレート Mod ジェネレータを使用できない場合は、次のステップを踏むことで手動で新しいプロジェクトを作成できます。</p><p>まず、Git を使用してサンプル Mod リポジトリをクローンします:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>このコマンドは、リポジトリを <code>my-mod-project</code> という名前のフォルダにクローンします。</p><p>続いて、フォルダ内の <code>.git</code> フォルダを削除し、IntelliJ IDEA でプロジェクトを開いてください。 <code>.git</code> フォルダが表示されない場合は、ファイルマネージャで隠しファイルの表示を有効にする必要があります。</p><p>プロジェクトを IntelliJ IDEA で開くと、IDE は自動で Gradle 設定を読み込み、セットアップに必要なタスクを行います。</p><p>前述の通り、Gradle ビルドスクリプトに関する通知が表示された場合は、<code>Gradle プロジェクトのインポート</code> ボタンを押してください。</p><h3 id="modifying-the-template" tabindex="-1">テンプレートの編集 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “テンプレートの編集”">​</a></h3><p>プロジェクトがインポートされたら、プロジェクトの詳細をあなたの Mod の詳細に合わせて編集してください:</p><ul><li><code>gradle.properties</code> ファイル内の <code>maven_group</code> と <code>archive_base_name</code> を編集します。</li><li><code>fabric.mod.json</code> ファイル内の <code>id</code>、<code>name</code>、<code>description</code> プロパティを編集します。</li><li>Minecraft、マッピング、Fabric Loader、Loom のバージョンを、対応させたい値に編集します。これらは <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> で照会できます。</li></ul><p>言うまでもないですが、パッケージ名と Mod のメインクラスも適宜編集してください。</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};